1207	    /// Pre-collect the chunks supplied by `reader` (a state-aware callback)
1208	    /// and forward the accumulated buffer to `lua_vm::api::load`. The streaming
1209	    /// loader in `lua_vm::api::load` consumes a `Box<dyn FnMut() -> Option<Vec<u8>>>`
1210	    /// that does not take a `&mut LuaState`, so the state-touching reader
1211	    /// (e.g. `generic_reader`, which calls a Lua function to produce each
1212	    /// chunk) is drained first. C-Lua streams chunks directly through
1213	    /// `lua_load`; the materialised path here is observable only for very
1214	    /// large source files and is intentional for the Phase-B shim.
1215	    fn load_with_reader<F, M: ?Sized>(&mut self, mut reader: F, name: &[u8], mode: &M) -> Result<bool, LuaError>
1216	    where
1217	        F: FnMut(&mut LuaState) -> Result<Option<Vec<u8>>, LuaError>,
1218	        M: AsRef<[u8]>,
1219	    {
1220	        let mut buf: Vec<u8> = Vec::new();
1221	        let mut reader_err: Option<LuaError> = None;
1222	        loop {
1223	            match reader(self) {
1224	                Err(e) => {
1225	                    reader_err = Some(e);
1226	                    break;
1227	                }
1228	                Ok(None) => break,
1229	                Ok(Some(piece)) => {
1230	                    if piece.is_empty() {
1231	                        break;
1232	                    }
1233	                    buf.extend_from_slice(&piece);
1234	                }
1235	            }
1236	        }
1237	        if let Some(e) = reader_err {
1238	            let msg_value = match e {
1239	                LuaError::Runtime(v) | LuaError::Syntax(v) => v,
1240	                LuaError::Memory => {
1241	                    let s = self.intern_str(b"not enough memory")?;
1242	                    LuaValue::Str(s)
1243	                }
1244	                _ => {
1245	                    let s = self.intern_str(b"error in reader function")?;
1246	                    LuaValue::Str(s)
1247	                }
1248	            };
1249	            self.push(msg_value);
1250	            return Ok(false);
1251	        }
1252	        let mut once = Some(buf);
1253	        let boxed: Box<dyn FnMut() -> Option<Vec<u8>>> = Box::new(move || once.take());
1254	        let mode_bytes = mode.as_ref();
1255	        let status = lua_vm::api::load(self, boxed, Some(name), Some(mode_bytes))?;
1256	        Ok(status == LuaStatus::Ok)
1257	    }
