1311	        let _ = self;
1312	    }
1313	
1314	    /// Install (or clear) a debug hook on this thread.
1315	    ///
1316	    /// C: `LUA_API void lua_sethook (lua_State *L, lua_Hook func, int mask, int count)`
1317	    /// (`ldebug.c`).
1318	    ///
1319	    /// The Phase-B `LuaStateStubExt` signature uses `lua_CFunction` (the
1320	    /// stdlib C-function shape: `fn(&mut LuaState) -> Result<usize, LuaError>`)
1321	    /// for `f`, whereas the canonical `lua_vm::debug::set_hook` takes a
1322	    /// `Box<dyn FnMut(&mut LuaState, &LuaDebug)>` (a true Lua hook, which has
1323	    /// access to the active `lua_Debug`). To bridge the two, an installed
1324	    /// `lua_CFunction` is wrapped in a trampoline closure that calls it with
1325	    /// `state` and discards both the activation record and the
1326	    /// `Result<usize, LuaError>` (a hook's return value is ignored by C-Lua).
1327	    fn set_hook_full(
1328	        &mut self,
1329	        f: Option<lua_CFunction>,
1330	        mask: u32,
1331	        count: i32,
1332	    ) -> Result<(), LuaError> {
1333	        let hook: Option<Box<dyn FnMut(&mut LuaState, &lua_vm::debug::LuaDebug)>> = match f {
1334	            None => None,
1335	            Some(func) => Some(Box::new(move |state, _ar| {
1336	                let _ = func(state);
1337	            })),
1338	        };
1339	        lua_vm::debug::set_hook(self, hook, mask as i32, count);
1340	        Ok(())
1341	    }
1342	
1343	    /// Write `msg` to the host's standard output stream.
1344	    ///
1345	    /// C: `lua_writestring(s, l)` macro from `lauxlib.h` (defaults to
1346	    /// `fwrite(s, 1, l, stdout)`).
1347	    ///
1348	    /// Delegates to the canonical inherent `LuaState::write_output`. UFCS is
1349	    /// used to disambiguate from the trait method (this method) which would
1350	    /// otherwise recurse.
1351	    fn write_output(&mut self, msg: &[u8]) -> Result<(), LuaError> {
1352	        LuaState::write_output(self, msg)
1353	    }
1354	
1355	    /// `t[n] = v`, where `t` is the value at `idx` and `v` is popped from the
1356	    /// stack top. Honours `__newindex`.
1357	    ///
1358	    /// C: `LUA_API void lua_seti (lua_State *L, int idx, lua_Integer n)`.
1359	    fn table_set_i(&mut self, idx: i32, n: i64) -> Result<(), LuaError> {
1360	        LuaState::table_set_i(self, idx, n)
1361	    }
1362	
1363	    /// Allocate a fresh full-userdata, push it on the stack, and return a
1364	    /// `GcRef` to it. `name` is advisory (callers typically follow up with
1365	    /// `set_metatable_by_name(name)`).
1366	    ///
1367	    /// C-correspondent: `lua_newuserdatauv(L, size, nuvalue)` plus the
1368	    /// auxiliary `luaL_setmetatable` pattern. The Rust signature carries
1369	    /// `name` for caller convenience as documented on the inherent method.
1370	    fn new_userdata_typed(
1371	        &mut self,
1372	        name: &[u8],
1373	        size: usize,
1374	        nuvalue: i32,
1375	    ) -> Result<GcRef<LuaUserData>, LuaError> {
1376	        LuaState::new_userdata_typed(self, name, size, nuvalue)
1377	    }
1378	}
1379	
1380	/// Copy populated fields from the canonical `lua_vm::debug::LuaDebug` into
1381	/// the Phase-B stub `LuaDebug`. The two structs diverge on a few field types
1382	/// (e.g. `what` is a single byte tag in the stub vs. `Option<&'static [u8]>`
1383	/// in the canonical struct, `short_src` is `Vec<u8>` vs. fixed array).
1384	/// Copy only the fields that `lua_getinfo`'s `what` string actually populates
1385	/// in C. Mirrors `auxgetinfo` in `ldebug.c`: each option byte writes a disjoint
1386	/// subset of `lua_Debug`. Calling `get_info` with one option string must not
1387	/// clobber fields populated by an earlier call with a different option string
1388	/// (a pattern the auxiliary library relies on — `pushglobalfuncname` calls
1389	/// `lua_getinfo(L, "f", ar)` and expects the previously-set `namewhat`/`what`/
1390	/// `short_src`/`linedefined` to survive).
1391	fn copy_lvm_debug_to_stub_selective(
1392	    src: &lua_vm::debug::LuaDebug,
1393	    dst: &mut LuaDebug,
1394	    what: &[u8],
1395	) {
1396	    dst.i_ci_idx = src.i_ci;
1397	    for &ch in what {
1398	        match ch {
1399	            b'S' => {
1400	                dst.what = match src.what {
1401	                    Some(b"Lua") => b'L',
1402	                    Some(b"C") => b'C',
1403	                    Some(b"main") => b'm',
1404	                    _ => 0,
1405	                };
1406	                dst.source = src.source.clone().unwrap_or_default();
1407	                let zero = src
1408	                    .short_src
1409	                    .iter()
1410	                    .position(|&b| b == 0)
1411	                    .unwrap_or(src.short_src.len());
1412	                dst.short_src = src.short_src[..zero].to_vec();
1413	                dst.linedefined = src.linedefined;
1414	                dst.lastlinedefined = src.lastlinedefined;
1415	            }
1416	            b'l' => {
1417	                dst.currentline = src.currentline;
1418	            }
1419	            b'u' => {
1420	                dst.nups = src.nups;
1421	                dst.nparams = src.nparams;
1422	                dst.isvararg = src.isvararg;
1423	            }
1424	            b't' => {
1425	                dst.istailcall = src.istailcall;
1426	            }
1427	            b'n' => {
1428	                dst.name = src.name.clone();
1429	                dst.namewhat = src.namewhat.map(|s| s.to_vec()).unwrap_or_default();
1430	            }
1431	            b'r' => {
1432	                dst.ftransfer = src.ftransfer;
1433	                dst.ntransfer = src.ntransfer;
1434	            }
1435	            _ => {}
1436	        }
1437	    }
1438	}
