                let got = self.value_at(arg);
                let got_name = self.full_type_name(&got)?;
                let extramsg = format!(
                    "string expected, got {}",
                    String::from_utf8_lossy(&got_name)
                );
                Err(lua_vm::debug::arg_error_impl(self, arg, extramsg.as_bytes()))
            }
        }
    }

